head.script:
scwin.gv_bondTransExpireDt = "";	//보세만료일자
scwin.gv_strExistTF = "";     	    //중복체크여부
scwin.arrParent0_0 = "";
scwin.arrParent0_1 = "";
scwin.arrParent0_2 = "";
scwin.arrParent0_3 = "";
scwin.arrParent0_4 = "";
scwin.arrParent0_5 = "";
scwin.arrParent0_6 = "";
scwin.arrParent0_7 = "";
scwin.arrParent0_8 = "";
scwin.arrParent0_9 = "";
scwin.pageOpenYn = "T";

scwin.arrParent1_0 = "";
scwin.arrParent1_1 = "";
scwin.arrParent1_2 = "";

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = async function () {
    scwin.params = $c.data.getParameter();


    //점소코드콤보


    //em_vehclShortCd.focus();

    //scwin.btn_retrieve_onclick();
};

//-------------------------------------------------------------------------
// 화면로딩시 UDC 호출
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function () {

    const codeOptions = [

        { grpCd: "ZZ307", compID: "acb_lc_wrkDstClsCd,gr_retrieveUsableVehiclesPresent:wrkDstCd" }
        , { grpCd: "ZZ617", compID: "gr_retrieveUsableVehiclesPresent:eqDriveWayCd" }
    ]
    $c.data.setCommonCode(codeOptions);
    var arr0 = scwin.params.data[0];            // 첫 번째 파라미터 그룹 객체
    var arr1 = scwin.params.data[1];           // 두 번째 파라미터 그룹 객체

    /*파라미터로 넘어온 값 매핑 */
    if (arr0 != null && arr0 != "" && arr0 != undefined) {

        scwin.arrParent0_0 = arr0[0];
        scwin.arrParent0_1 = arr0[1];
        scwin.arrParent0_2 = arr0[2];
        scwin.arrParent0_3 = arr0[3];
        scwin.arrParent0_4 = arr0[4];
        scwin.arrParent0_5 = arr0[5];
        scwin.arrParent0_6 = arr0[6];
        scwin.arrParent0_7 = arr0[7];
        scwin.arrParent0_8 = arr0[8];
        scwin.arrParent0_9 = arr0[9];
        scwin.arrParent1_0 = arr1[0];
        scwin.arrParent1_1 = arr1[1];
        scwin.arrParent1_2 = arr1[2];
    }

    if(scwin.arrParent1_2 == "D")
    {
        $c.sbm.execute(sbm_loBranCMDD);
    }
    else
    {
        $c.sbm.execute(sbm_loBranCMD);
    }


    //차량종류콤보
    await scwin.f_vehclKnd();

    //화물구분콤보
    await scwin.f_cargoCls();

    //업체구분콤보
    await scwin.f_RetrieveSecondCoCls(scwin.arrParent0_3);
    /* test data end */

    if (arr1 != null && arr1 != "" && arr1 != undefined) {

        scwin.gv_bondTransExpireDt = scwin.arrParent1_0;	//보세만료일자
        scwin.gv_strExistTF = scwin.arrParent1_1;
    }

    dma_search.set("lobranCd", scwin.arrParent0_0);
    dma_search.set("wrkDst", scwin.arrParent0_1);
    dma_search.set("district", scwin.arrParent0_2);
    dma_search.set("cargoClsCd", scwin.arrParent0_3);
    dma_search.set("usblDt", scwin.arrParent0_4);
    dma_search.set("vehclShortCd", scwin.arrParent0_5);
    dma_search.set("clntNo", scwin.arrParent0_6);
    dma_search.set("schCond", scwin.arrParent0_8);
    dma_search.set("vehclKnd", scwin.arrParent0_9);

    if(scwin.arrParent1_2 == "D")
    {
        $c.sbm.execute(sbm_retrieveD);    
    }
    else
    {
        $c.sbm.execute(sbm_retrieve);
    }    

    acb_lc_wrkDstClsCd.setValue(scwin.arrParent0_1); //작업구간
    acb_lc_vehclKnd.setValue(scwin.arrParent0_9); //차량종류
    ica_em_usblDt.setValue(scwin.arrParent0_4);
    em_vehclShortCd.setValue(scwin.arrParent0_5);
    em_clntNo.setValue(scwin.arrParent0_6);
    txt_clntNm.setValue(scwin.arrParent0_7);


};

//-------------------------------------------------------------------------
// 백스페이스(8) 키 누름 시
//-------------------------------------------------------------------------
scwin.Go_searchPopup = function () {

};

//-------------------------------------------------------------------------
// 차량종류 콤보
//-------------------------------------------------------------------------
scwin.f_vehclKnd = async function () {
    dma_combo_in.set("sysCd", "EquipmentNonUsableEBC");
    dma_combo_in.set("queryId", "retriveKindCodeListCombo");

    await $c.sbm.execute(sbm_vehclKnd);
};

//-------------------------------------------------------------------------
// 차량종류 규격 콤보
//-------------------------------------------------------------------------
scwin.f_vehclNrm = function (param1) {
    dma_combo_in.set("sysCd", "EquipmentNonUsableEBC");
    dma_combo_in.set("queryId", "retrivecComboNrmCodeList");
    dma_combo_in.set("param1", param1);

    $c.sbm.execute(sbm_comboCMD);
};

//-------------------------------------------------------------------------
// 운송화물 구분 콤보
//-------------------------------------------------------------------------
scwin.f_cargoCls = function () {
    dma_combo_in.set("sysCd", "EquipmentNonUsableEBC");
    dma_combo_in.set("queryId", "retriveCargoCodeListCombo");

    $c.sbm.execute(sbm_comboCMD);
};

//-------------------------------------------------------------------------
// 업체 구분 콤보
//-------------------------------------------------------------------------
scwin.f_RetrieveSecondCoCls = function (param1) {
    dma_combo_in.set("sysCd", "EquipmentNonUsableEBC");
    dma_combo_in.set("queryId", "retrivecCoClsComboCodeList");
    dma_combo_in.set("param1", param1);

    $c.sbm.execute(sbm_comboCMD);
};

//-------------------------------------------------------------------------
// 권역 구분 콤보
//-------------------------------------------------------------------------
scwin.f_RetrieveDistrict = function (param1) {
    dma_combo_in.set("sysCd", "EquipmentNonUsableEBC");
    dma_combo_in.set("queryId", "retriveDistrictCombo");
    dma_combo_in.set("param1", param1);

    $c.sbm.execute(sbm_comboCMD);
};

//-------------------------------------------------------------------------
// 조회조건 필드 Clear
//-------------------------------------------------------------------------
scwin.btn_fieldClear_onclick = function (e) {
    $c.gus.cfInitObjects(tb_srchCond, [acb_lc_lobranCd, acb_lc_cargoClsCd, ica_em_usblDt]); //2번째 인자는 초기화 제외 대상인듯?
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.btn_retrieve_onclick = function (e) {
    //필수값 체크
    if (!$c.gus.cfValidate([ica_em_usblDt])) return;

    if(scwin.arrParent1_2 == "D")
    {
        $c.sbm.execute(sbm_retrieveD);    
    }
    else
    {
        $c.sbm.execute(sbm_retrieve);
    }   
//    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    totalRows.setValue(ds_results.getRowCount());

    if (ds_results.getRowCount() == 0) {
        !$c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }
    if (ds_results.getRowCount() == 1 && scwin.gv_strExistTF == 'T')	{
        scwin.f_rtnValuecwin(0);
    }
    ds_results.setRowPosition(1);
    gr_retrieveUsableVehiclesPresent.setFocusedCell(0, 0);
};

//-------------------------------------------------------------------------
// Windows Close
//-------------------------------------------------------------------------
scwin.btn_close_onclick = function (e) {
    let rt = "N/A";

    $c.win.closePopup();
};

scwin.gr_retrieveUsableVehiclesPresent_oncelldblclick = function (rowIndex, columnIndex, columnId) {
    scwin.f_rtnValuecwin(rowIndex);
};

//-------------------------------------------------------------------------
// 결과값 리턴
//-------------------------------------------------------------------------
scwin.f_rtnValuecwin = function (row) {
    let i = row;

    if (scwin.gv_bondTransExpireDt != "") {
        var v_bondTransStDt = ds_results.getCellData(i, "bondTransStDt");	//보세운송 시작일자
        var v_bondTransEndDt = ds_results.getCellData(i, "bondTransEndDt");	//보세운송 종료일자

        if (ds_results.getCellData(i, "bondTransVehclYn") == "0" || !$c.gus.cfIsAfterDate(gv_bondTransExpireDt, v_bondTransEndDt, false)) {
            $c.gus.cfAlertMsg("보세운송 등록일자가 만료되었거나 등록차량이 아닙니다");
            return;
        }

        var v_diff = cfDaysBetween(gv_bondTransExpireDt, v_bondTransEndDt);
        if (v_diff <= 15) {
            cfAlertMsg("보세운송일자 갱신일이 " + v_diff + "일 남았습니다. 참고하십시오");
        }

    }

    if (ds_results.getCellData(i, "eqStsCd") == "NA") {
        if (!$c.gus.cfConfirmMsg("차량번호" + ds_results.getCellData(i, "vehclNo") + "는 비가용차량입니다.\n계속하시겠습니까?")) {
            return;
        }
    }
    else if (ds_results.getCellData(i, "eqStsCd") == "ON") {
        if (!$c.gus.cfConfirmMsg("차량번호" + ds_results.getCellData(i, "vehclNo") + "는 사용중인 차량입니다.\n계속하시겠습니까?")) {
            return;
        }
    }

    let rt = [ds_results.getCellData(i, "eqCd")
        , ds_results.getCellData(i, "vehclNo")
        , ds_results.getCellData(i, "vehclShortCd")
        , ds_results.getCellData(i, "bondTransStDt")
        , ds_results.getCellData(i, "bondTransEndDt")
        , ds_results.getCellData(i, "drvEmpNo")
        , ds_results.getCellData(i, "drvNm")
        , ds_results.getCellData(i, "drvTelNo")
        , ds_results.getCellData(i, "trsNo")
        , ds_results.getCellData(i, "vehclIdCardNo")
        , ds_results.getCellData(i, "logisLnkEqCd")
        , ds_results.getCellData(i, "chassisNo")
        , ds_results.getCellData(i, "eqKndCd")
        , ds_results.getCellData(i, "eqNrmCd")
        , ds_results.getCellData(i, "chk")
        , ds_results.getCellData(i, "clntNo")
        , ds_results.getCellData(i, "posnClsCd")
        , ds_results.getCellData(i, "mpNo")
    ];

    $c.win.closePopup([rt]);
};

/*-- 협력업체 UDC 이벤트 --*/
scwin.udc_clntNo_onblurCodeEvent = function (e) {
    udc_clntNo.openPopup(em_clntNo.getValue(), txt_clntNm.getValue(), "");
};

scwin.udc_clntNo_onclickEvent = async function (e) {
    scwin.f_openCommonPopUp(1, em_clntNo.getValue(), txt_clntNm.getValue(), 'T', "F");
};

/*-- 차량종류 콤보이벤트 --*/
scwin.acb_lc_vehclKnd_onchange = function (info) {
    scwin.f_vehclNrm(acb_lc_vehclKnd.getValue());
};

/*-- 운송화물구분 콤보이벤트 --*/
scwin.acb_lc_cargoClsCd_onchange = function (info) {
    let gubun = acb_lc_cargoClsCd.getValue();
    if (scwin.pageOpenYn == "F") {
        scwin.f_RetrieveSecondCoCls(gubun);
    }

    //index == 0
    if (info.newValue == "T") {
        gr_retrieveUsableVehiclesPresent.setHeaderValue("column41", "대표화종1");
        gr_retrieveUsableVehiclesPresent.setHeaderValue("column39", "대표화종2");
    }
    //index == 1
    else if (info.newValue == "B") {
        gr_retrieveUsableVehiclesPresent.setHeaderValue("column41", "샤시종류");
        gr_retrieveUsableVehiclesPresent.setHeaderValue("column39", "샤시규격");
    }
    //index == 2 인 컨테이너 확인 필요

    if (gubun == 'B') {
        scwin.f_RetrieveDistrict('BWK');
    } else if (gubun == 'C') {
        scwin.f_RetrieveDistrict('CMP');
    }

    //$c.gus.cfStyleGrid(gr_retrieveUsableVehiclesPresent, "comn");
};

scwin.f_gridColumnData = function (chk) {
    return $c.gus.decode(chk, 0, "가용", 1, "SPOT");
};

scwin.sbm_comboCMD_submitdone = function (e) {
    let requestBody = JSON.parse(e.requestBody).GAUCE.queryId;

    if (requestBody == "retriveKindCodeListCombo") {
        dlt_vehclKnd.setJSON(e.responseJSON.GAUCE);

        acb_lc_vehclKnd.setSelectedIndex(0);
    }

    if (requestBody == "retriveCargoCodeListCombo") {
        dlt_cargoCls.setJSON(e.responseJSON.GAUCE);

        // acb_lc_cargoClsCd.setValue(scwin.arrParent0_3);
    }

    if (requestBody == "retrivecComboNrmCodeList") {
        dlt_vehclNrm.setJSON(e.responseJSON.GAUCE);

        acb_lc_vehclNrm.setSelectedIndex(0);
    }

    if (requestBody == "retrivecCoClsComboCodeList") {
        dlt_clntNo.setJSON(e.responseJSON.GAUCE);

        acb_lc_clntNo.setSelectedIndex(0);
        if (scwin.pageOpenYn == "T") {
            acb_lc_cargoClsCd.setValue(scwin.arrParent0_3);
            scwin.pageOpenYn = "F";
        }
    }

    if (requestBody == "retriveDistrictCombo") {
        dlt_districtCd.setJSON(e.responseJSON.GAUCE);

        acb_lc_districtCd.setValue(scwin.arrParent0_2);
    }

};

scwin.sbm_loBranCMD_submitdone = function (e) {
    acb_lc_lobranCd.setValue(scwin.arrParent0_0);
};
//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {

    switch (disGubun) {
        case 1:
            // 협력업체(차량매입)
            udc_clntNo.setSelectId('retrieveCarKindClntInfo');
            udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callBackFunc   // XML상의 SELECT ID
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서
                , null					// 보여주는 각 컬럼들의 폭
                , null					// 컬럼중에서 숨기는	컬럼 지정
                , "01"   // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이
                , null					// 윈도우 위치 Y좌표
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch				// 전체검색허용여부	("F")
                , "협력업체,협력업체코드,협력업체명"	// POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;
    }
};

scwin.udc_clntNo_callBackFunc = function (rtnList) {
    //cfSetReturnValue(rtnList, em_clntNo, txt_clntNm);
    em_clntNo.setValue(rtnList[0]);
    txt_clntNm.setValue(rtnList[1]);
};
